module sync_counter(rst, enable, reset, count);

    input rst;
    input enable;
    input reset;
    output [3:0] count;
    reg [3:0] count;
    initial count = 0;

    always @(posedge rst)
        begin
            if (reset)
                count <= 0;
            else if (enable)
                count <= count + 1;
        end

endmodule
